 1→function apiBaseUrl() {
 2→  return (
 3→    process.env.NEXT_PUBLIC_API_BASE_URL?.replace(/\/+$/, "") ||
 4→    "http://localhost:8080"
 5→  );
 6→}
 7→
 8→export type RequestJSONInit = RequestInit & {
 9→  token?: string;
10→  // For GET requests, allow Next.js caching when desired.
11→  next?: { revalidate?: number };
12→};
13→
14→export async function requestJSON<T>(
15→  path: string,
16→  init: RequestJSONInit = {},
17→): Promise<T> {
18→  const headers = new Headers(init.headers);
19→  headers.set("Content-Type", "application/json");
20→  if (init.token) headers.set("Authorization", `Bearer ${init.token}`);
21→
22→  const method = (init.method ?? "GET").toUpperCase();
23→  const cache = method === "GET" && init.next ? "force-cache" : "no-store";
24→
25→  const res = await fetch(`${apiBaseUrl()}${path}`, {
26→    ...init,
27→    headers,
28→    cache,
29→  });
30→
31→  if (!res.ok) {
32→    const text = await res.text().catch(() => "");
33→    throw new Error(`API ${res.status}: ${text || res.statusText}`);
34→  }
35→
36→  return (await res.json()) as T;
37→}
38→
39→export function getApiBaseUrlForDebug() {
40→  return apiBaseUrl();
41→}
