 31→function formatWindowLabel(w: SellerPickupWindow): string {
 32→  const start = new Date(w.start_at);
 33→  const end = new Date(w.end_at);
 34→  if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) {
 35→    return `Window (${w.status})`;
 36→  }
 37→  return `${start.toLocaleString()}–${end.toLocaleTimeString()} (${w.status})`;
 38→}
