 40→export default function SellerStorePage() {
 41→  const params = useParams<{ storeId: string }>();
 42→  const storeId = params.storeId;
 43→  const router = useRouter();
 44→  const { showToast, clearToast } = useToast();
 45→
 46→  const [token, setToken] = useState<string | null>(null);
 47→  const [error, setError] = useState<string | null>(null);
 48→
 49→  const [, setLocations] = useState<SellerPickupLocation[] | null>(null);
 50→  const [windows, setWindows] = useState<SellerPickupWindow[] | null>(null);
 51→  const [, setProducts] = useState<SellerProduct[] | null>(null);
 52→  const [, setOfferings] = useState<SellerOffering[] | null>(null);
 53→  const [orders, setOrders] = useState<SellerOrder[] | null>(null);
 54→  const [payoutSummary, setPayoutSummary] = useState<SellerPayoutSummary | null>(
 55→    null,
 56→  );
 57→  const [plans, setPlans] = useState<SellerSubscriptionPlan[] | null>(null);
 58→
 59→  const [selectedWindowId, setSelectedWindowId] = useState<string>("");
 60→  const [orderFilter, setOrderFilter] = useState<OrderFilter>("all");
 61→  const [supportOpen, setSupportOpen] = useState(false);
 62→  const supportBtnRef = useRef<HTMLButtonElement | null>(null);
 63→  const supportPanelRef = useRef<HTMLDivElement | null>(null);
 64→  const [supportPos, setSupportPos] = useState<{ top: number; left: number } | null>(null);
 65→  const [pickupCodeByOrderId, setPickupCodeByOrderId] = useState<
 66→    Record<string, string>
 67→  >({});
 68→  const [generatingCycle, setGeneratingCycle] = useState(false);
 69→  const [busyOrderId, setBusyOrderId] = useState<string | null>(null);
 70→  const [togglingPlan, setTogglingPlan] = useState(false);
 71→  const [confirmAction, setConfirmAction] = useState<{
 72→    title: string;
 73→    message: string;
 74→    confirmLabel: string;
 75→    destructive: boolean;
 76→    action: () => void;
 77→  } | null>(null);
 78→
 79→  const selectedWindow = useMemo(() => {
 80→    if (!selectedWindowId) return null;
 81→    return (windows ?? []).find((w) => w.id === selectedWindowId) ?? null;
 82→  }, [windows, selectedWindowId]);
 83→
 84→  const filteredOrders = useMemo(() => {
 85→    if (!orders) return null;
 86→    if (orderFilter === "all") return orders;
 87→    return orders.filter((o) => o.status === orderFilter);
 88→  }, [orders, orderFilter]);
 89→
 90→  const orderCounts = useMemo(() => {
 91→    const base: Record<OrderFilter, number> = {
 92→      all: 0,
 93→      placed: 0,
 94→      ready: 0,
 95→      picked_up: 0,
 96→      no_show: 0,
 97→      canceled: 0,
 98→    };
 99→    if (!orders) return base;
100→    base.all = orders.length;
101→    for (const o of orders) {
102→      const k = o.status as OrderFilter;
103→      if (k in base) base[k] += 1;
104→    }
105→    return base;
106→  }, [orders]);
107→
108→  const siteOrigin = useMemo(() => {
109→    if (typeof window === "undefined") return "";
110→    return window.location.origin;
111→  }, []);
112→
113→  // Redirect to setup if no live plan
114→  useEffect(() => {
115→    if (plans !== null && !plans.some((p) => p.is_live)) {
116→      router.replace(`/seller/stores/${storeId}/setup`);
117→    }
118→  }, [plans, storeId, router]);
119→
120→  useEffect(() => {
121→    const t = session.getToken();
122→    if (!t) {
123→      router.replace("/seller/login");
124→      return;
125→    }
126→    setToken(t);
127→  }, [router]);
128→
129→  useLayoutEffect(() => {
130→    if (!supportOpen) return;
131→
132→    const update = () => {
133→      const btn = supportBtnRef.current;
134→      if (!btn) return;
135→      const rect = btn.getBoundingClientRect();
136→      const w = 288; // matches w-[18rem]
137→      const pad = 10;
138→      const left = Math.max(
139→        pad,
140→        Math.min(rect.right - w, window.innerWidth - w - pad),
141→      );
142→      const top = Math.min(rect.bottom + 10, window.innerHeight - 20);
143→      setSupportPos({ top, left });
144→    };
145→
146→    update();
147→    window.addEventListener("resize", update);
148→    window.addEventListener("scroll", update, true);
149→    return () => {
150→      window.removeEventListener("resize", update);
151→      window.removeEventListener("scroll", update, true);
152→    };
153→  }, [supportOpen]);
154→
155→  useEffect(() => {
156→    if (!supportOpen) return;
157→    const onDown = (e: MouseEvent) => {
158→      const t = e.target as Node | null;
159→      if (!t) return;
160→      if (supportBtnRef.current?.contains(t)) return;
161→      if (supportPanelRef.current?.contains(t)) return;
162→      setSupportOpen(false);
163→    };
164→    const onKey = (e: KeyboardEvent) => {
165→      if (e.key === "Escape") setSupportOpen(false);
166→    };
167→    window.addEventListener("mousedown", onDown);
168→    window.addEventListener("keydown", onKey);
169→    return () => {
170→      window.removeEventListener("mousedown", onDown);
171→      window.removeEventListener("keydown", onKey);
172→    };
173→  }, [supportOpen]);
174→
175→  async function refreshAll(t: string) {
176→    const [ls, ws, ps, sps] = await Promise.all([
177→      sellerApi.listPickupLocations(t, storeId),
178→      sellerApi.listPickupWindows(t, storeId),
179→      sellerApi.listProducts(t, storeId),
180→      sellerApi.listSubscriptionPlans(t, storeId),
181→    ]);
182→    setLocations(ls);
183→    setWindows(ws);
184→    setProducts(ps);
185→    setPlans(sps);
186→    setSelectedWindowId((prev) => {
187→      if (prev && ws.some((w) => w.id === prev)) return prev;
188→      return ws[0]?.id ?? "";
189→    });
190→  }
191→
192→  useEffect(() => {
193→    if (!token) return;
194→    setError(null);
195→    refreshAll(token).catch((e: unknown) => {
196→      const apiErr = parseApiError(e);
197→      if (apiErr && apiErr.status === 403) {
198→        showToast({ kind: "error", message: "You don\u2019t have access to that store." });
199→        router.replace("/seller");
200→        return;
201→      }
202→      if (apiErr && apiErr.status === 404) {
203→        showToast({ kind: "error", message: "Store not found." });
204→        router.replace("/seller");
205→        return;
206→      }
207→      setError(friendlyErrorMessage(e));
208→    });
209→    // eslint-disable-next-line react-hooks/exhaustive-deps
210→  }, [token, storeId]);
211→
212→  useEffect(() => {
213→    if (!token || !selectedWindowId) return;
214→    setError(null);
215→    sellerApi
216→      .listOfferings(token, storeId, selectedWindowId)
217→      .then(setOfferings)
218→      .catch((e: unknown) => setError(friendlyErrorMessage(e)));
219→  }, [token, storeId, selectedWindowId]);
220→
221→  useEffect(() => {
222→    if (!token || !selectedWindowId) return;
223→    setError(null);
224→    sellerApi
225→      .listOrders(token, storeId, selectedWindowId)
226→      .then(setOrders)
227→      .catch((e: unknown) => setError(friendlyErrorMessage(e)));
228→  }, [token, storeId, selectedWindowId]);
229→
230→  useEffect(() => {
231→    if (!token || !selectedWindowId) return;
232→    sellerApi
233→      .getPayoutSummary(token, storeId, selectedWindowId)
234→      .then(setPayoutSummary)
235→      .catch(() => setPayoutSummary(null));
236→  }, [token, storeId, selectedWindowId]);
237→
238→  async function generateNextCycle(planId: string) {
239→    if (!token) return;
240→    setError(null);
241→    clearToast();
242→    setGeneratingCycle(true);
243→    try {
244→      const res = await sellerApi.generateNextCycle(token, storeId, planId);
245→      await refreshAll(token);
246→      setSelectedWindowId(res.pickup_window_id);
247→      showToast({
248→        kind: "success",
249→        message: "Pickup cycle generated. You are now live.",
250→      });
251→    } catch (e: unknown) {
252→      setError(friendlyErrorMessage(e));
253→      showToast({ kind: "error", message: "Could not generate pickup cycle." });
254→    } finally {
255→      setGeneratingCycle(false);
256→    }
257→  }
258→
259→  function togglePlanActive(planId: string, currentlyActive: boolean) {
260→    if (!token) return;
261→    const action = currentlyActive ? "pause" : "resume";
262→    setConfirmAction({
263→      title: currentlyActive ? "Pause box?" : "Resume box?",
264→      message: currentlyActive
265→        ? "It will stop appearing for new buyers."
266→        : "It will be visible to buyers again.",
267→      confirmLabel: currentlyActive ? "Pause" : "Resume",
268→      destructive: currentlyActive,
269→      action: async () => {
270→        setTogglingPlan(true);
271→        setError(null);
272→        try {
273→          await sellerApi.updateSubscriptionPlan(token, storeId, planId, {
274→            is_active: !currentlyActive,
275→          });
276→          await refreshAll(token);
277→          showToast({
278→            kind: "success",
279→            message: action === "pause" ? "Box paused." : "Box resumed.",
280→          });
281→        } catch (e: unknown) {
282→          setError(friendlyErrorMessage(e));
283→          showToast({ kind: "error", message: `Could not ${action} box.` });
284→        } finally {
285→          setTogglingPlan(false);
286→        }
287→      },
288→    });
289→  }
290→
291→  async function setOrderStatus(
292→    orderId: string,
293→    status: "ready" | "canceled" | "no_show",
294→    opts?: { waive_fee?: boolean },
295→  ) {
296→    if (!token || !selectedWindowId) return;
297→    if (status === "canceled") {
298→      setConfirmAction({
299→        title: "Cancel order?",
300→        message: "This will release reserved inventory.",
301→        confirmLabel: "Cancel order",
302→        destructive: true,
303→        action: () => executeOrderStatus(orderId, status, opts),
304→      });
305→      return;
306→    }
307→    if (status === "no_show") {
308→      setConfirmAction({
309→        title: "Mark as no-show?",
310→        message: "This will release reserved inventory.",
311→        confirmLabel: "Mark no-show",
312→        destructive: true,
313→        action: () => executeOrderStatus(orderId, status, opts),
314→      });
315→      return;
316→    }
317→    executeOrderStatus(orderId, status, opts);
318→  }
319→
320→  async function executeOrderStatus(
321→    orderId: string,
322→    status: "ready" | "canceled" | "no_show",
323→    opts?: { waive_fee?: boolean },
324→  ) {
325→    if (!token || !selectedWindowId) return;
326→    setBusyOrderId(orderId);
327→    setError(null);
328→    try {
329→      await sellerApi.updateOrderStatus(token, storeId, orderId, status, opts);
330→      // Refresh both orders and offerings since inventory may have changed.
331→      const [os, ofs] = await Promise.all([
332→        sellerApi.listOrders(token, storeId, selectedWindowId),
333→        sellerApi.listOfferings(token, storeId, selectedWindowId),
334→      ]);
335→      setOrders(os);
336→      setOfferings(ofs);
337→      const labels: Record<string, string> = {
338→        ready: "Order marked ready.",
339→        canceled: "Order canceled.",
340→        no_show: "Marked as no-show.",
341→      };
342→      showToast({ kind: "success", message: labels[status] ?? "Order updated." });
343→    } catch (e: unknown) {
344→      setError(friendlyErrorMessage(e));
345→    } finally {
346→      setBusyOrderId(null);
