926→                            }
927→                            disabled={busyOrderId === o.id}
928→                            title="Void the authorization (waive fee)."
929→                          >
930→                            No show (waive)
931→                          </button>
932→                        </div>
933→                      </>
934→                    ) : null}
935→                  </div>
936→                </div>
937→              </li>
938→            ))}
939→          </ul>
940→        ) : selectedWindowId ? (
941→          <div className="text-sm text-[color:var(--lr-muted)]">
942→            No orders yet for this window.
943→          </div>
944→        ) : (
945→          <div className="text-sm text-[color:var(--lr-muted)]">
946→            Select an active pickup window above to view orders.
947→          </div>
948→        )}
949→      </section>
950→      </div>
951→
952→      <ConfirmDialog
953→        open={confirmAction !== null}
954→        title={confirmAction?.title ?? ""}
955→        message={confirmAction?.message ?? ""}
956→        confirmLabel={confirmAction?.confirmLabel ?? "Confirm"}
957→        destructive={confirmAction?.destructive ?? false}
958→        onConfirm={() => {
959→          confirmAction?.action();
960→          setConfirmAction(null);
961→        }}
962→        onCancel={() => setConfirmAction(null)}
963→      />
964→    </div>
